<script setup lang="ts">import { computed, reactive, ref } from 'vue'; import type { CategoryNode, ItemInput } from '../../catalog/catalogModels'; const props=defineProps<{categories:CategoryNode[];initial?:Partial<ItemInput>;pending?:boolean}>(); const emit=defineEmits<{save:[ItemInput]}>(); const error=ref(''); const form=reactive({name:props.initial?.name??'',categoryId:props.initial?.categoryId??'',defaultUnit:props.initial?.defaultUnit??'个',brand:props.initial?.brand??null,model:null,specification:null,defaultShelfLifeValue:null,defaultShelfLifeUnit:null,customAttributes:{} as Record<string,unknown>,barcodes:[] as string[],tags:[] as string[],version:props.initial?.version}); const category=computed(()=>props.categories.find(c=>c.id===form.categoryId)); const barcode=ref(''); function addBarcode(){const raw=barcode.value.trim();if(!raw)return;if(form.barcodes.some(v=>v.toUpperCase()===raw.toUpperCase())){error.value='条码不能重复';return}form.barcodes.push(raw);barcode.value=''} function save(){if(!form.name.trim()||!form.categoryId){error.value='请填写名称和分类';return}emit('save',{...form} as ItemInput)}</script>
<template><form @submit.prevent="save"><p v-if="error" role="alert">{{ error }}</p><label>物品名称<input v-model="form.name" required /></label><label>分类<select v-model="form.categoryId" required><option value="">请选择</option><option v-for="c in categories" :key="c.id" :value="c.id">{{ c.name }}</option></select></label><label>默认单位<input v-model="form.defaultUnit" /></label><label v-for="field in category?.attributeSchema" :key="field.key">{{ field.label }}<input v-if="field.type==='TEXT'||field.type==='DATE'||field.type==='NUMBER'" v-model="form.customAttributes[field.key]" :type="field.type==='NUMBER'?'number':field.type==='DATE'?'date':'text'"/><input v-else-if="field.type==='BOOLEAN'" v-model="form.customAttributes[field.key]" type="checkbox"/><select v-else v-model="form.customAttributes[field.key]"><option v-for="option in field.options" :key="option">{{ option }}</option></select></label><label>添加条码<input v-model="barcode" @keydown.enter.prevent="addBarcode" /></label><ul><li v-for="code in form.barcodes" :key="code">{{ code }}</li></ul><button type="submit" :disabled="pending">{{ pending?'正在保存':'保存物品' }}</button></form></template>
